def percentil_nivel_lector(items: list[dict], grado: int, edad: int | None = None) -> dict | None:
    """Percentil TEDE de Nivel Lector a partir de los ítems de la sesión.

    El TEDE puntúa en percentiles por edad y por curso, y esa es una medida de
    gravedad normada —de 1974, con estandarización de Berdicewsky, Milicic y
    Orellana— frente a la severidad del modelo, que todavía no tiene ninguna
    etiqueta de especialista para validarse. Tener las dos al lado permite ver
    si coinciden; que difieran también es información.

    **Solo Nivel Lector.** El TEDE tiene un segundo subtest, Errores
    Específicos, que puntúa sobre 71 ítems fijos restando los errores
    cometidos. Nuestro conteo de errores (INV, SUS, OMI, ROT...) no se
    corresponde con esos 71 ítems, así que llevarlo a esa tabla produciría un
    número con apariencia normativa y sin fundamento. Se omite a propósito.

    Devuelve None si no hay ítems de lectura: es preferible no informar
    percentil a informar uno inventado.
    """
    lectura = [i for i in items if i.get("module") == "lectura_voz_alta"]
    if not lectura:
        return None

    aciertos = sum(1 for i in lectura if i.get("is_correct"))
    administrados = len(lectura)

    # El baremo del TEDE está calibrado sobre los 100 ítems del subtest. Como
    # la sesión presenta una muestra, el puntaje se lleva a esa escala. Es una
    # aproximación: escalar supone que la muestra tiene la misma dificultad
    # media que el subtest completo, que es justamente lo que garantiza el
    # muestreo estratificado, pero con menos ítems el margen de error crece.
    escalado = administrados < 100
    puntaje = round(aciertos / administrados * 100) if escalado else aciertos

    percentiles = tede_percentil(puntaje, "nivel_lector", edad=edad, grado=grado)
    if not percentiles:
        return None

    return {
        **percentiles,
        "subtest": "nivel_lector",
        "aciertos": aciertos,
        "items_administrados": administrados,
        "puntaje_escala_tede": puntaje,
        # Se informa para que quien lea el percentil sepa cuánta confianza
        # darle: no es lo mismo derivarlo de 100 ítems que de 30.
        "escalado": escalado,
        "fuente": "TEDE Condemarín-Blomquist, estandarización 1974",
    }


def tede_percentil(puntaje: int, subtest: str = "nivel_lector",
                    edad: int = None, grado: int = None) -> dict:
    tabla = TEDE_PERCENTILES[subtest]
    result = {}
    for ref_type, ref_val in [("edad", edad), ("grado", grado)]:
        if ref_val is None:
            continue
        key_map = tabla[f"por_{ref_type}"]
        claves = list(key_map.keys())
        ref_val_clamped = min(claves, key=lambda k: abs(k - ref_val))
        rangos = key_map[ref_val_clamped]
        percentil = None
        for pmin, pmax, perc in rangos:
            if pmin <= puntaje <= pmax:
                percentil = perc
                break
        if percentil is None:
            percentil = 100 if puntaje >= rangos[-1][1] else 1
        result[f"percentil_por_{ref_type}"] = percentil
    return result
